5	/**
6	 * Generate a simple access token with tenantId claim
7	 * @param {Object} payload - { username, tenantId, role }
8	 * @returns {string} signed JWT
9	 */
10	const generateSimpleToken = ({ username, tenantId, role }) => {
11	  const expires = moment().add(config.jwt.accessExpirationMinutes, 'minutes');
12	  return jwt.sign(
13	    {
14	      sub: username,
15	      tenantId,
16	      role,
17	      iat: moment().unix(),
18	      exp: expires.unix(),
19	      type: 'access',
20	    },
21	    config.jwt.secret
22	  );
23	};
24	
25	module.exports = { generateSimpleToken };
